mapper.select:
SELECT *
FROM verification_code
WHERE username = #{username}
  AND code = #{code}
  AND purpose = #{purpose}
  AND used = 0
  AND expire_time > NOW()
ORDER BY create_time DESC
LIMIT 1

mapper.update:
UPDATE verification_code
SET used = 1
WHERE id = #{id}

mapper.delete:
DELETE FROM verification_code
WHERE username = #{username}
  AND purpose = #{purpose}
